  ('evt_001', '2026-02-28T07:23:00.000Z', 'Iran''s supreme leader dead following major attack by U.S., Israel', 'geopolitical_conflict', 35.6892, 51.389, 'Tehran, Iran', 'AP', 'https://spectrumlocalnews.com/us/snplus/international/2026/02/28/israel-launches-attack-on-iran-s-capital-with-u-s--help-as-tensions-high-over-nuclear-talks', '2026-02-28T07:23:00.000Z', '2026-03-01T02:07:00.000Z', '{evt_002}', 'direct', 2.2069969795957234),
